using UnityEngine;using UnityEngine.UI;using TMPro;using System.Collections;
public class UIManager : MonoBehaviour{public static UIManager Instance{get;private set;}[SerializeField]private TextMeshProUGUI scoreText,comboText;[SerializeField]private Image nextPreview;[SerializeField]private CanvasGroup comboPanel;[SerializeField]private GameObject gameOverPanel;[SerializeField]private TextMeshProUGUI finalScoreText;[SerializeField]private Button restartBtn,shareBtn,watchAdBtn;[SerializeField]private GameObject floatScorePrefab;[SerializeField]private Transform floatParent;private void Awake(){if(Instance==null)Instance=this;else{Destroy(gameObject);return;}}private void OnEnable(){if(ScoreManager.Instance!=null)ScoreManager.Instance.OnScoreChanged+=US;if(ComboSystem.Instance!=null)ComboSystem.Instance.OnComboUpdated+=UC;if(GameManager.Instance!=null){GameManager.Instance.OnGameOver+=GO;GameManager.Instance.OnGameStart+=GS;}if(restartBtn)restartBtn.onClick.AddListener(()=>GameManager.Instance?.RestartGame());if(shareBtn)shareBtn.onClick.AddListener(()=>ShareManager.Instance?.ShareScore(ScoreManager.Instance.CurrentScore));if(watchAdBtn)watchAdBtn.onClick.AddListener(()=>AdManager.Instance?.ShowRewardedAd(AdManager.RewardType.Revive));}private void OnDisable(){if(ScoreManager.Instance!=null)ScoreManager.Instance.OnScoreChanged-=US;if(ComboSystem.Instance!=null)ComboSystem.Instance.OnComboUpdated-=UC;if(GameManager.Instance!=null){GameManager.Instance.OnGameOver-=GO;GameManager.Instance.OnGameStart-=GS;}}public void UpdatePreview(Sprite s){if(nextPreview&&s){nextPreview.sprite=s;nextPreview.enabled=true;}}private void US(int s){if(scoreText)scoreText.text=s.ToString("N0");}private void UC(int c,int m){if(comboText==null||comboPanel==null)return;if(c>=2){comboPanel.gameObject.SetActive(true);comboText.text=$"x{m} COMBO!";comboPanel.alpha=1;}else StartCoroutine(FC());}private IEnumerator FC(){if(!comboPanel)yield break;float e=0;while(e<0.5f){e+=Time.deltaTime;comboPanel.alpha=Mathf.Lerp(1,0,e/0.5f);yield return null;}comboPanel.gameObject.SetActive(false);comboPanel.alpha=1;}private void GO(){if(!gameOverPanel)return;gameOverPanel.SetActive(true);if(finalScoreText)finalScoreText.text="SCORE\n"+ScoreManager.Instance.CurrentScore.ToString("N0");}private void GS(){if(gameOverPanel)gameOverPanel.SetActive(false);US(0);UC(0,1);}public void ShowFloatingScore(Vector2 wp,int s){if(!floatScorePrefab)return;var sp=Camera.main.WorldToScreenPoint(wp);var o=Instantiate(floatScorePrefab,floatParent);o.transform.position=sp;var t=o.GetComponentInChildren<TextMeshProUGUI>();if(t)t.text="+"+s.ToString("N0");Destroy(o,1f);}}